import React, { useEffect, useState } from 'react';
import { get, post } from '../api';

export default function UsersList() {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(false);
  const [processing, setProcessing] = useState(false);

  async function fetchUsers() {
    setLoading(true);
    try {
      const res = await get('/api/admin-lists/users');
      setUsers(res.data);
    } catch (err) {
      console.error(err);
      alert('Failed to load users');
    } finally {
      setLoading(false);
    }
  }

  async function removeDuplicates() {
    if (!window.confirm('This will delete duplicate users (keep earliest). Continue?')) return;
    setProcessing(true);
    try {
      const res = await post('/api/admin-lists/users/remove-duplicates', {});
      alert(`Deleted ${res.data.deleted} duplicate users`);
      await fetchUsers();
    } catch (err) {
      console.error(err);
      alert('Failed to remove duplicates');
    } finally {
      setProcessing(false);
    }
  }

  useEffect(() => {
    fetchUsers();
  }, []);

  return (
    <div>
      <h2>Users</h2>
      <div style={{ marginBottom: 12 }}>
        <button onClick={fetchUsers} disabled={loading} style={{ marginRight: 8 }}>Refresh</button>
        <button onClick={removeDuplicates} disabled={processing}>Remove Duplicates (by Phone)</button>
      </div>
      {loading ? (
        <div>Loading...</div>
      ) : (
        <table border="1" cellPadding="8" style={{ borderCollapse: 'collapse' }}>
          <thead>
            <tr>
              <th>Id</th>
              <th>Phone</th>
              <th>Consent</th>
              <th>Phone Verified</th>
              <th>Saved Address</th>
              <th>Created At</th>
            </tr>
          </thead>
          <tbody>
            {users.map(u => (
              <tr key={u.id}>
                <td>{u.id}</td>
                <td>{u.phone}</td>
                <td>{u.consentAccepted ? 'Yes' : 'No'}</td>
                <td>{u.phoneVerified ? 'Yes' : 'No'}</td>
                <td>{u.savedAddress}</td>
                <td>{new Date(u.createdAt).toLocaleString()}</td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
}
